class FreqStack:

    def __init__(self):
        self.stack = []
        self.freq = {}

    def push(self, val: int) -> None:
        if val not in self.freq:
            self.freq[val] = 0
        self.freq[val] += 1
        self.stack.append((val, self.freq[val]))

    def pop(self) -> int:
        max_freq = max(self.freq.values())
        res = None
        for val, freq in self.stack:
            if freq == max_freq:
                res = val
                break
        self.stack.remove((res, max_freq))
        self.freq[res] -= 1
        return res
